// 倍增
void solve(int CASE)
{
	ll n, c, q; cin >> n >> c >> q;
	var a = vector<ll>(n);
	fa(i, 0, n - 1)cin >> a[i];
	var p = Vec2<ll>(n + 1, 31);
	var dp = Vec2<ll>(n + 1, 31);
	fa(i, 0, n - 1) {
		ll nex = (i + a[i]) % n;
		p[i][0] = nex;
		dp[i][0] = a[i];
	}
	fa(j, 1, 30)
		fa(i, 0, n - 1) {
		p[i][j] = p[p[i][j - 1]][j - 1];
		dp[i][j] = dp[i][j - 1] + dp[p[i][j - 1]][j - 1];
	}
	while (q--) {
		ll x; cin >> x;
		if (x > c)cout << "No" << endl;
		else if (x == c)cout << "Yes" << endl;
		else {
			ll cha = c - x;
			ll now = x % n;
			fb(i, 30, 0) {
				if (cha >= dp[now][i]) {
					cha -= dp[now][i];
					now = p[now][i];
				}
			}
			if (cha)cout << "No" << endl;
			else cout << "Yes" << endl;
		}
	}
	return;
}

// 基环树+同余最短路+找环
void solve(int CASE)
{
	ll n, c, q; cin >> n >> c >> q;
	var a = vector<ll>(n);
	fa(i, 0, n - 1)cin >> a[i];

	var g = vector<vector<int>>(n);
	var nex = vector<int>(n);
	fa(i, 0, n - 1) {
		nex[i] = (i + a[i]) % n;
		g[nex[i]].pb(i);
	}

	var Q = queue<int>();
	var dis = vector<ll>(n, LNF);
	var vis = vector<bool>(n);
	ll st = c % n;
	dis[st] = 0;
	Q.push(st);
	while (Q.size()) {
		int now = Q.front();
		Q.pop();
		if (vis[now])continue;
		vis[now] = 1;
		for (int to : g[now]) {
			if (dis[to] > dis[now] + a[to]) {
				dis[to] = dis[now] + a[to]; // 注意 + a[to]
				Q.push(to);
			}
		}
	}

	fill(all(vis), 0);
	ll sum = 0, now = st;
	while (!vis[now]) {
		vis[now] = 1;
		sum += a[now];
		now = nex[now];
	}
	if (now != st)sum = -1;

	while (q--) {
		ll x; cin >> x;
		if (x > c)cout << "No" << endl;
		else if (x == c)cout << "Yes" << endl;
		else {
			ll now = x % n;
			if (dis[now] == LNF) {
				cout << "No" << endl;
				continue;
			}
			x += dis[now];
			if (x == c)cout << "Yes" << endl;
			else if (x < c) {
				ll cha = c - x;
				if (sum != -1 and (c - x) % sum == 0)cout << "Yes" << endl;
				else cout << "No" << endl;
			}
			else cout << "No" << endl;
		}
	}
	return;
}
